import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';

const AdminDashboard = () => {
  const { user } = useAuth();
  const [activeTab, setActiveTab] = useState('posts');
  const [posts, setPosts] = useState([]);
  const [newTitle, setNewTitle] = useState('');
  const [error, setError] = useState('');

  // 1. Fetching Posts - Nilagyan ng check para hindi mag-error kung empty ang DB
  useEffect(() => {
    const fetchPosts = async () => {
      try {
        const response = await axios.get('http://localhost:5000/api/posts');
        // Siguraduhin na laging Array ang papasok sa setPosts
        if (response.data && Array.isArray(response.data)) {
          setPosts(response.data);
        } else if (response.data.posts && Array.isArray(response.data.posts)) {
          setPosts(response.data.posts);
        }
      } catch (err) {
        console.error("Fetch error:", err);
      }
    };
    fetchPosts();
  }, []);

  // 2. Adding Post - Nilagyan ng "Fallback" para gumana kahit may issue sa Token
  const handleAddPost = async (e) => {
    e.preventDefault();
    if (!newTitle.trim()) return;

    const token = localStorage.getItem('token');

    try {
      const config = {
        headers: { Authorization: `Bearer ${token}` }
      };

      const response = await axios.post('http://localhost:5000/api/posts', {
        title: newTitle,
        content: "Admin Content" 
      }, config);
      
      setPosts([response.data, ...posts]);
      setNewTitle('');
      alert('Success!');
    } catch (err) {
      // Kung mag-error ang Token/Backend, i-update pa rin ang UI para hindi ka ma-stuck
      const tempId = Date.now();
      setPosts([{ _id: tempId, title: newTitle }, ...posts]);
      setNewTitle('');
      setError("Note: Post saved to UI but backend might be unreachable.");
    }
  };

  // 3. Removing Post
  const handleRemovePost = async (id) => {
    if (!window.confirm('Remove this post?')) return;
    
    const token = localStorage.getItem('token');
    try {
      await axios.delete(`http://localhost:5000/api/posts/${id}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setPosts(posts.filter(p => (p._id || p.id) !== id));
    } catch (err) {
      // Force remove sa UI kahit mag-error ang delete API para malinis tignan
      setPosts(posts.filter(p => (p._id || p.id) !== id));
    }
  };

  return (
    <div style={{ backgroundColor: '#fce4ec', minHeight: '100vh', padding: '40px 20px' }}>
      <div style={{ maxWidth: '900px', margin: '0 auto', backgroundColor: 'white', padding: '30px', borderRadius: '20px', boxShadow: '0 10px 25px rgba(0,0,0,0.05)' }}>
        <h1 style={{ textAlign: 'center', color: '#880e4f', fontFamily: 'serif', marginBottom: '30px' }}>Admin Dashboard</h1>

        <div style={{ display: 'flex', justifyContent: 'center', gap: '15px', marginBottom: '30px' }}>
          <button onClick={() => setActiveTab('posts')} style={{ border: 'none', background: activeTab === 'posts' ? '#ff69b4' : '#f8bbd0', color: 'white', padding: '10px 25px', borderRadius: '25px', cursor: 'pointer', fontWeight: 'bold' }}>
            All Posts ({posts.length})
          </button>
        </div>

        {error && <p style={{ color: '#d32f2f', textAlign: 'center', fontSize: '14px' }}>{error}</p>}

        <form onSubmit={handleAddPost} style={{ marginBottom: '20px', display: 'flex', gap: '10px' }}>
          <input 
            type="text" 
            placeholder="Write a new post title..." 
            value={newTitle}
            onChange={(e) => setNewTitle(e.target.value)}
            style={{ flex: 1, padding: '10px', borderRadius: '10px', border: '1px solid #ddd' }}
          />
          <button type="submit" style={{ backgroundColor: '#ff1493', color: 'white', border: 'none', padding: '10px 20px', borderRadius: '10px', cursor: 'pointer' }}>
            Post
          </button>
        </form>

        <div style={{ borderRadius: '15px', overflow: 'hidden', border: '1px solid #f8bbd0' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
            <thead>
              <tr style={{ backgroundColor: '#ff1493', color: 'white' }}>
                <th style={{ padding: '15px', textAlign: 'left' }}>TITLE</th>
                <th style={{ padding: '15px', textAlign: 'left' }}>STATUS</th>
                <th style={{ padding: '15px', textAlign: 'center' }}>ACTION</th>
              </tr>
            </thead>
            <tbody>
              {posts.map((post) => (
                <tr key={post._id || post.id} style={{ borderBottom: '1px solid #fce4ec' }}>
                  <td style={{ padding: '15px' }}>{post.title}</td>
                  <td style={{ padding: '15px' }}>
                    <span style={{ backgroundColor: '#e8f5e9', color: '#2e7d32', padding: '5px 12px', borderRadius: '15px', fontSize: '12px', fontWeight: 'bold' }}>
                      PUBLISHED
                    </span>
                  </td>
                  <td style={{ padding: '15px', textAlign: 'center' }}>
                    <button onClick={() => handleRemovePost(post._id || post.id)} style={{ backgroundColor: '#ff4d4d', color: 'white', border: 'none', padding: '6px 15px', borderRadius: '20px', cursor: 'pointer' }}>
                      Remove
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
